%%
%[text] ## Model DH Constantes
%[text] ![](text:image:46e7)
% Constantes do Modelo
Jx = 43.244/1000;
Jy = 84.404/1000;
1/Jy;
Jz = 126.192/1000;
Jxz = 1.571/1000;

gamma0 = (Jx*Jz)-Jxz^2;
gamma(1) = (Jxz*(Jx-Jy+Jz))/gamma0;
gamma(2) = (Jz*(Jz-Jy)+Jxz^2)/gamma0;
gamma(3) = Jz/gamma0;
gamma(4) = Jxz/gamma0;
gamma(5) = (Jz-Jx)/Jy;
gamma(6) = Jxz/Jy;
gamma(7) = (Jx*(Jx-Jy)+Jxz^2)/gamma0;
gamma(8) = Jx/gamma0;
m = 1072.011/1000;
g = 9.81;
rx(1) = 0.311185;
ry(1) = 0.232;

rx(2) = -0.342865;
ry(2) = -0.232;

rx(3) = 0.311185;
ry(3) = -0.232;

rx(4) = -0.342865;
ry(4) = 0.232;
%%
%[text] ## Passo 1: Verificar recriação de Atitude
%[text] Recriar atitude com os dados do log de voo \[p,q,r\], para validar equação, e verificar o grau de erro de medição incluído no sinal de velocidades angulares.
% Dados de entrada
% Tempo
t = t_common(idx_range);
dt = 0.1;

% Velocidade Angular
p = gyrX_interp(idx_range);  % rad/s
q = gyrY_interp(idx_range);
r = gyrZ_interp(idx_range);

% Ângulos de atitude reais
phi_real = roll_interp(idx_range);
theta_real = pitch_interp(idx_range);
psi_real = yaw_interp(idx_range);

% Inicialização dos ângulos de atitude
phi   = zeros(size(t));
theta = zeros(size(t));
psi   = zeros(size(t));

% Valores Iniciais
phi(1) = deg2rad(phi_real(1));
theta(1) = deg2rad(theta_real(1));
psi(1) = deg2rad(psi_real(1));

% Loop de integração
for k = 1:length(t)-1
    % Valores atuais
    phi_k = phi(k);
    theta_k = theta(k);

    % Matriz de transformação T(phi, theta)
    T = [ 1,        sin(phi_k)*tan(theta_k),  cos(phi_k)*tan(theta_k);
          0,        cos(phi_k),              -sin(phi_k);
          0,        sin(phi_k)/cos(theta_k),  cos(phi_k)/cos(theta_k) ];

    % Vetor de velocidades angulares
    omega = [p(k); q(k); r(k)];

    % Derivada dos ângulos de Euler
    euler_dot = T * omega;

    % Integração (método de Euler)
    phi(k+1)   = phi(k)   + euler_dot(1) * dt;
    theta(k+1) = theta(k) + euler_dot(2) * dt;
    psi(k+1)   = psi(k)   + euler_dot(3) * dt;
end

% Opcional: converter para graus para visualização
phi_deg   = rad2deg(phi);
theta_deg = rad2deg(theta);
psi_deg   = rad2deg(psi);

% Plot
figure;
subplot(3,1,1)
plot(t,phi_real,'r');grid on; hold on;
plot(t,phi_deg,'b');grid on;
title('Atitude [°]');
legend('\phi_{real} [°]', '\phi_{simulado} [°]');
subplot(3,1,2)
plot(t,theta_real,'r');grid on; hold on;
plot(t,theta_deg,'b');grid on;
legend('\theta_{real} [°]', '\theta_{simulado} [°]');
subplot(3,1,3)
plot(t,psi_real,'r');grid on; hold on;
plot(t,psi_deg,'b');grid on;
legend('\psi_{real} [°]', '\psi_{simulado} [°]');
xlabel('Tempo [s]');
%%
%[text] ## Passo 2: Verificar recriação de Posição
% Dados de entrada
t = t_common(idx_range);
dt = 0.1;
N = length(t);

% Velocidade Angular
p = gyrX_interp(idx_range);  % rad/s
q = gyrY_interp(idx_range);
r = gyrZ_interp(idx_range);

% Aceleração
accX = accX_interp(idx_range);  % rad/s
accY = accY_interp(idx_range);
accZ = accZ_interp(idx_range);

% Ângulos de atitude reais
phi_real = roll_interp(idx_range);
theta_real = pitch_interp(idx_range);
psi_real = yaw_interp(idx_range);

% Posição Real
x_real = Pn;
y_real = E;
z_real = -D;

% Inicialização dos ângulos de atitude
phi   = zeros(size(t));
theta = zeros(size(t));
psi   = zeros(size(t));

% Inicialização dos ângulos de atitude
ax = zeros(size(t));
ay = zeros(size(t));
az = zeros(size(t));

% Valores Iniciais
phi(1) = deg2rad(phi_real(1));
theta(1) = deg2rad(theta_real(1));
psi(1) = deg2rad(psi_real(1));

velNED = zeros(N, 3);
posNED = zeros(N, 3);

for k = 1:N-1
    % --- Leitura dos dados instantâneos
    ax = accX(k); ay = accY(k); az = accZ(k);    % no sistema do corpo
    phi_k = phi(k); theta_k = theta(k); psi_k = psi(k);
    p_k = p(k); q_k = q(k); r_k = r(k);

    % --- Matriz de transformação
    T = [1, sin(phi_k)*tan(theta_k), cos(phi_k)*tan(theta_k);
         0, cos(phi_k),             -sin(phi_k);
         0, sin(phi_k)/cos(theta_k), cos(phi_k)/cos(theta_k)];

    % Derivadas da atitude
    att_dot = T * [p_k; q_k; r_k];

    % Integração
    phi(k+1) = phi(k) + att_dot(1)*dt;
    theta(k+1) = theta(k) + att_dot(2)*dt;
    psi(k+1) = psi(k) + att_dot(3)*dt;

    % --- Matriz de rotação do corpo para NED
    R_bn = [ ...
        cos(theta_k)*cos(psi_k),  cos(theta_k)*sin(psi_k), -sin(theta_k);
        sin(phi_k)*sin(theta_k)*cos(psi_k)-cos(phi_k)*sin(psi_k), ...
        sin(phi_k)*sin(theta_k)*sin(psi_k)+cos(phi_k)*cos(psi_k), ...
        sin(phi_k)*cos(theta_k);
        cos(phi_k)*sin(theta_k)*cos(psi_k)+sin(phi_k)*sin(psi_k), ...
        cos(phi_k)*sin(theta_k)*sin(psi_k)-sin(phi_k)*cos(psi_k), ...
        cos(phi_k)*cos(theta_k) ];

    % --- Vetor aceleração no corpo
    acc_body = [ax; ay; az];

    % --- Aceleração no NED (transformada)
    acc_NED = R_bn * acc_body;

    % --- Corrigir gravidade (subtrair do eixo D)
    acc_NED(3) = acc_NED(3) + g;

    % --- Integrar para obter velocidade
    velNED(k+1,:) = velNED(k,:) + acc_NED' * dt;

    % --- Integrar para obter posição
    posNED(k+1,:) = posNED(k,:) + velNED(k,:) * dt;
end

figure;
subplot(3,1,1)
plot(t,x_real,'r');grid on; hold on;
plot(t,posNED(:,1),'b');grid on;
title('Passo 2: Reconstrução da Posição');
legend('N_{real} [m]', 'N_{calc} [m]');
subplot(3,1,2)
plot(t,y_real,'r');grid on; hold on;
plot(t,posNED(:,2),'b');grid on;
legend('E_{real} [m]', 'E_{calc} [m]');
subplot(3,1,3)
plot(t,z_real,'r');grid on; hold on;
plot(t,-posNED(:,3),'b');grid on;
legend('D_{real} [m]', 'D_{calc} [m]');
xlabel('Tempo [s]');
%%
%[text] ## Passo 3: Verificar recriação de Posição com motores
%[text] entrada: Dados de Atitude \[phi, theta, yaw\], de velocidades angulares \[p,q,r\] e dos empuxos \[Tmr1, Tmr2, Tmr3, Tmr4\]
% Dados de entrada
t = t_common(idx_range);
dt = 0.1;
N = length(t);
m = 2385.011/1000;

% Dados de Entrada
T_mr1 = T_mr1_interp(idx_range);
T_mr2 = T_mr2_interp(idx_range);
T_mr3 = T_mr3_interp(idx_range);
T_mr4 = T_mr4_interp(idx_range);

% Empuxo total dos motores
Tmr = T_mr1 + T_mr2 + T_mr3 + T_mr4;
Tmr = Tmr*1;

% Velocidades Angulares
p = gyrX_interp(idx_range);  % rad/s
q = gyrY_interp(idx_range);
r = gyrZ_interp(idx_range);

pBias = mean(p);
qBias = mean(p);
rBias = mean(p);

% Atitudes
phi = deg2rad(roll_interp(idx_range));
theta = deg2rad(pitch_interp(idx_range));
psi = deg2rad(yaw_interp(idx_range));

% Aceleração
u_dot_real = accX_interp(idx_range);
v_dot_real = accY_interp(idx_range);
w_dot_real = accZ_interp(idx_range);

u_real = zeros(1,N); v_real = zeros(1,N); w_real = zeros(1,N);   % velocidade linear

x_real = Pn;
y_real = E;
z_real = -D;

% Inicialização
g = 9.81;            % gravidade [m/s^2]

% Inicialização dos vetores de estado
u_dot = zeros(1,N); v_dot = zeros(1,N); w_dot = zeros(1,N);   % aceleração linear
u = zeros(1,N); v = zeros(1,N); w = zeros(1,N);   % velocidade linear
x = zeros(1,N); y = zeros(1,N); z = zeros(1,N);   % posição no corpo

% Loop de integração
for k = 1:N-1
    % Leitura instantânea
    phi_k = phi(k);
    theta_k = theta(k);
    psi_k = psi(k);
    
    p_k = p(k);
    q_k = q(k);
    r_k = r(k);
    
    u_k = u(k);
    v_k = v(k);
    w_k = w(k);
    
    % Vetor gravidade no mundo
    Fg_inertial = [0; 0; m * g];
    
    R_bn = [ ...
            cos(theta_k)*cos(psi_k),  cos(theta_k)*sin(psi_k), -sin(theta_k);
            sin(phi_k)*sin(theta_k)*cos(psi_k)-cos(phi_k)*sin(psi_k), ...
            sin(phi_k)*sin(theta_k)*sin(psi_k)+cos(phi_k)*cos(psi_k), ...
            sin(phi_k)*cos(theta_k);
            cos(phi_k)*sin(theta_k)*cos(psi_k)+sin(phi_k)*sin(psi_k), ...
            cos(phi_k)*sin(theta_k)*sin(psi_k)-sin(phi_k)*cos(psi_k), ...
            cos(phi_k)*cos(theta_k) ];
    
    % Gravidade transformada para o corpo
    Fg_body = R_bn' * Fg_inertial;  % (gravidade em corpo)
    
    % Força total
    F_body = Fg_body + [0; 0; -Tmr(k)];

    % Dinâmica translacional
    u_dot(k+1) = r_k*v_k - q_k*w_k + (1/m) * F_body(1);
    v_dot(k+1) = p_k*w_k - r_k*u_k + (1/m) * F_body(2);
    w_dot(k+1) = q_k*u_k - p_k*v_k + (1/m) * F_body(3);

    % Integração de velocidade
    u(k+1) = u(k) + u_dot(k) * dt;
    v(k+1) = v(k) + v_dot(k) * dt;
    w(k+1) = w(k) + w_dot(k) * dt;

    % Integração da velocidadde real
    u_real(k+1) = u_real(k) + u_dot_real(k) * dt;
    v_real(k+1) = v_real(k) + v_dot_real(k) * dt;
    w_real(k+1) = w_real(k) + w_dot_real(k) * dt;

    % Integração de posição (no sistema do corpo, pode converter para NED depois)
    uvw_k = [u(k); v(k); w(k)];
    vNED_k = R_bn * uvw_k;
    
    x(k+1) = x(k) + vNED_k(1) * dt;
    y(k+1) = y(k) + vNED_k(2) * dt;
    z(k+1) = z(k) + vNED_k(3) * dt;
end

% Plot
figure;
subplot(3,1,1)
plot(t,u_dot_real,'r');grid on; hold on;
plot(t,u_dot,'b');grid on;
title('Aceleração [m/s^2]');
