title('Passo3: Reconstrução da Posição');
legend('N_{real} [m]', 'N_{calc} [m]');
subplot(3,1,2)
plot(t,y_real,'r');grid on; hold on;
plot(t,y,'b');grid on;
legend('E_{real} [m]', 'E_{calc} [m]');
