save('quad_model_v3.mat', 'pwm1_in', 'pwm2_in', 'pwm3_in', 'pwm4_in', 'p_out', 'q_out', 'r_out', 'u_dot_out', 'v_dot_out', 'w_dot_out', 'phi_out', 'theta_out', 'psi_out', 'phi0', 'theta0', 'psi0', 'P_estimated', 'p_bias', 'q_bias', 'r_bias')
